  public static ModuleKey fromString(String s) throws ParseException {
    if (s.equals("<root>")) {
      return ROOT;
    }
    int at = s.indexOf('@');
    if (at == -1) {
      throw new ParseException("Module key string missing '@' delimiter: " + s);
    }
    String name = s.substring(0, at);
    if (name.isEmpty()) {
      throw new ParseException("Module name cannot be empty for non-root module key: " + s);
    }
    String version = s.substring(at + 1);
    return create(name, version.equals("_") ? Version.EMPTY : Version.parse(version));
