    constexpr int to_int(const std::wstring_view& str, unsigned long base = 0) noexcept
    {
        if (str.empty())
        {
            return to_int_error;
        }

        const bool hasSign = str.front() == L'-';
        const auto result = hasSign ? to_ulong(str.substr(1), base) : to_ulong(str, base);

        // Check that result is valid and will fit in an int.
        // For negative numbers, the maximum magnitude is INT_MAX + 1 (i.e., abs(INT_MIN)).
        const auto maxMagnitude = hasSign ? static_cast<unsigned long>(INT_MAX) + 1 : static_cast<unsigned long>(INT_MAX);
        if (result == to_ulong_error || result > maxMagnitude)
        {
            return to_int_error;
        }

        // For the INT_MIN case, result == INT_MAX + 1, and negating it correctly yields INT_MIN.
        return hasSign ? -static_cast<int>(result) : static_cast<int>(result);
    }

